window.__QUIZ_DATA__=[{"id":"theory>Biology Practical>2002>1>a","subject":"Biology Practical","year":"2002","type":"Practical","sub_label":"a","group":"","topic":"CONCEPT OF LIVING : CELL AND ITS ENVIRONMENT","question":"Specimen A in group I is potassium permanganate crystals Carry out the following instructions using it  i. Half fill a 250cm3 beaker with distilled water or clean water  ii. Place the beaker of water on a flat table  iii. Using a spatula/small spoon introduce/drop gently a crystal of the permanganate into the beaker with water undisturbed  iv. Observe the colour of the contents in the beaker at the following intervals, immediately after dropping the crystal, 05 minutes, 15 minutes and 30 minutes  v. Make your recording of time (minutes) and observation/ inference as shown in the format below in your answer booklet  vi. Make a labelled drawing of 6cm to 8cm of the beaker and its contents as it appears after 15 minutes","images":["data:image/jpeg;base64,"],"marking_scheme":"Specimen A Potassium permanganate crystals in water  TIME (MINS)OBSERVATION/INFERENCEI. Immediately after dropping the crystalsA trail of purple colour follows the crystals to the bottom of the beakerII. 05 minutes laterThe crystal dissolves to form a dense purple colour at the bot tom of the beaker and a light layer on top As the molecules of potassium permanganate crystals move from region of high concentration to region of lower concentrationIII. 15 minutes laterThe whole water is coloured with three distinct layers; deep purple at the bottom; light purple at the middle and lighter purple on top. As diffusion takes placeIV. 30 minutesThe whole medium becomes uniformly purple coloured as the molecules of potassium permanganate are uniformly distributed    Drawing of beaker with contents at 15 (mins) after","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2002>1>b","subject":"Biology Practical","year":"2002","type":"Practical","sub_label":"b","group":"","topic":"CONCEPT OF LIVING : CELL AND ITS ENVIRONMENT","question":"What physiological process does the experiment you have just performed demonstrate?","images":[],"marking_scheme":"The physiological process is diffusion","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2002>1>c","subject":"Biology Practical","year":"2002","type":"Practical","sub_label":"c","group":"","topic":"CONCEPT OF LIVING : CELL AND ITS ENVIRONMENT","question":"Suggest a suitable title for the experiment","images":[],"marking_scheme":"Studying the process of diffusion through a liquid medium, using potassium permanganate crystals.","marks":"1","difficulty":"1"},{"id":"theory>Biology Practical>2002>1>d>i","subject":"Biology Practical","year":"2002","type":"Practical","sub_label":"i","group":"","topic":"CONCEPT OF LIVING : CELL AND ITS ENVIRONMENT","question":"In what medium did the experiment take place? Name any other medium that can be used for this experiment","images":[],"marking_scheme":"The experiment takes place in a liquid medium Other medium the experiment can takes place is air gas or solid","marks":"1","difficulty":"1"},{"id":"theory>Biology Practical>2002>1>d>ii","subject":"Biology Practical","year":"2002","type":"Practical","sub_label":"ii","group":"","topic":"CONCEPT OF LIVING : CELL AND ITS ENVIRONMENT","question":"Give two conditions that can speed up the rate of the process mentioned in 1b above","images":[],"marking_scheme":"The conditions that can speed up the rate of the process mentioned in 1 (b) above are  -increased temperature or heating  -smaller particle size  -high concentration gradient  -shaking or steering","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2002>1>e","subject":"Biology Practical","year":"2002","type":"Practical","sub_label":"e","group":"","topic":"CONCEPT OF LIVING : CELL AND ITS ENVIRONMENT","question":"State two instances in human, where the above process is significant","images":[],"marking_scheme":"The instance in human in which the process of diffusion can take place are  -The process of absorption of digested food into the villi in the small intestine  -The exchange of gases during respiration in the alveolli of lungs, gills of fishes, trachea of insects, skin of toads and stomata of leaves  -Diffusion of nutrients and gases from mother through placenta to foetus and waste products from foetus through the placenta to the mother","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2002>2>a>i","subject":"Biology Practical","year":"2002","type":"Practical","sub_label":"i","group":"","topic":"PLANT AND ANIMAL NUTRITION : ALIMENTARY SYSTEM","question":"Specimin B in group I is a fresh liver lobe of a small mammal. Examine the specimen carefully    Describe the specimen","images":[],"marking_scheme":"Specimen B is whole fresh liver lobe of a small mammal (Rabbit).The description of the specimen B it is dark red in colour, soft but firm to touch. It is fairly large in size with oval shape","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2002>2>a>ii","subject":"Biology Practical","year":"2002","type":"Practical","sub_label":"ii","group":"","topic":"PLANT AND ANIMAL NUTRITION : ALIMENTARY SYSTEM","question":"Mention the name of the structure you can see apart from the liver lobe Describe it Pierce the structure with a clean sharp dissecting pin/office pin","images":[],"marking_scheme":"The structure seen apart from the liver lobe is the gall bladder The gall bladder can be described as greenish yellow in colour, baglike and soft to touch","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2002>2>a>iii","subject":"Biology Practical","year":"2002","type":"Practical","sub_label":"iii","group":"","topic":"PLANT AND ANIMAL NUTRITION : ALIMENTARY SYSTEM","question":"Test the oozing content with a red litmus paper. Record your observation and state the pH of the content","images":[],"marking_scheme":"The oozing content turns red litmus paper blue. The pH is above","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2002>2>a>iv","subject":"Biology Practical","year":"2002","type":"Practical","sub_label":"iv","group":"","topic":"PLANT AND ANIMAL NUTRITION : ALIMENTARY SYSTEM","question":"Name the oozing substance and where it is manufactured","images":[],"marking_scheme":"The nozing substance bile and is manufactured in the liver","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2002>2>a>v","subject":"Biology Practical","year":"2002","type":"Practical","sub_label":"v","group":"","topic":"PLANT AND ANIMAL NUTRITION : ALIMENTARY SYSTEM","question":"State three functions of the substance named in 2(a)(iv)","images":[],"marking_scheme":"-It neutralizes the acidity of (hyme that leaves the stomach  -It provides suitable pH (neutral to alkaline for pancreatic juice to function during digestion  -It emulsify fats and oils to tiny droplets of fatty acids and glycerol thereby reducing the surface tension of the fats and oils   -It prevents decay of food in the small intestine","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2002>2>a>vi","subject":"Biology Practical","year":"2002","type":"Practical","sub_label":"vi","group":"","topic":"PLANT AND ANIMAL NUTRITION : ALIMENTARY SYSTEM","question":"List three functions and two diseases of the liver","images":[],"marking_scheme":"-it stores glycogen  -it deaminates amino acids to form urea  -it manufactures bie  -it forms plasma proteins such as fibrinogen and prothombin necessary for blood clothing  -it produces heat for constant body temperature  -it stores iron, copper or potassium  -it stores blood  -It forms erythrocytes in embryo  -It detoxifies harmful drugs and toxins  -it destroys worn out red blood cells  The diseases of the liver are  -Jaundice  -Hepatitis  -Cancer of the liver  -Liver cirrhosis  -gall stones","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2002>2>a>vii","subject":"Biology Practical","year":"2002","type":"Practical","sub_label":"vii","group":"","topic":"PLANT AND ANIMAL NUTRITION : ALIMENTARY SYSTEM","question":"Suggest the system in the mammalian/human-body associated with specimen B","images":[],"marking_scheme":"The Alimentary (digestive) system","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2002>2>b>i","subject":"Biology Practical","year":"2002","type":"Practical","sub_label":"i","group":"","topic":"CONCEPT OF LIVING : CLASSIFICATION","question":"Specimen C in group I is a mango fruit and specimen F in group III is an okro fruit    Classify specimens C and F into the type of fruits they belong","images":[],"marking_scheme":"Mango is a drupe (C)   Okra is a capsule (F)","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2002>2>b>ii","subject":"Biology Practical","year":"2002","type":"Practical","sub_label":"ii","group":"","topic":"CONCEPT OF LIVING : CLASSIFICATION","question":"Tabulate three differences between specimens C and F","images":[],"marking_scheme":"Specimen C (mango)Specimen F (Okro)It has one seedIt has many seedsIt has no line of splitsIt has many lines of spits (for dispersal)It has kidney shapeIt is oblongIt has smooth body surfaceit has hairy body surface","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2002>3>a>i","subject":"Biology Practical","year":"2002","type":"Practical","sub_label":"i","group":"","topic":"CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS","question":"Specimen D in group Ill is the whole of a pelvic girdle and specimen E in group II is the femur Both specimens are obtained from a small mammal    Give four observable features each, of specimen D, a pelvic  girdle and specimen E, a femur.","images":[],"marking_scheme":"Observable features of specimen D (Pelvic girdle)  -There are presence of ilium, ischium, and pubis which fuse together to form innominate bone  -There are presence of concave articulating surface called acetabulum. -There are large holes called oburator foramen.   -There are presence of facet for articulation with sacrum  Observable features of Specimen E (Femur)  -It has a long shaft with a round head at one end.   -The head has a short neck.   -There are presence of great trochanter, patellar groove and condule","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2002>3>a>ii","subject":"Biology Practical","year":"2002","type":"Practical","sub_label":"ii","group":"","topic":"CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS","question":"State three functions each, of specimens D and E","images":[],"marking_scheme":"Specimen D (Pelvic girdle):   -It has surface for muscle attachment   -it protect some reproductive organs   -It support the sacrum.   -It forms ball and socket joint with femur for movement of the lower limb   -It has oburator foramen as a passage for nerves and blood vessels.  Specimen E (Femur):   -It support the upper leg.   -It is involved in the formation of red blood cells (RBC) in the bone mar row   -It provides articulating surfaces for the tibia or fibula   -It forms ball and socket joint with the pelvic girdle   -It has patellar groove which articulates with patellar (knee cap)","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2002>3>a>iii","subject":"Biology Practical","year":"2002","type":"Practical","sub_label":"iii","group":"","topic":"CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS","question":"State how specimen D is adapted to articulate with specimen E","images":[],"marking_scheme":"How specimen D (Pelvic girdle) is adapted to articulate with specimen E. (left femur). It has a deep concave articulating surface (deep acetabulum) which admits the entire head of specimen E to form ball and socket joint The short neck suspending the head of Femur assists in this union","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2002>3>a>iv","subject":"Biology Practical","year":"2002","type":"Practical","sub_label":"iv","group":"","topic":"CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS","question":"Name a nutrient contained in specimen D and E. What function does this nutrient perform in the human body?","images":[],"marking_scheme":"The nutrient contained in D & E are  -calcium  -phosphorus  -Calcium phosphate  The function of the nutrient  -It is needed for formation of strong bones and teeth  -It is involved in blood ciotting   -It is required for proper functioning of the liver or nervous system  -It is involved in normal contraction of muscles   -Phosphorus is needed for the regulation of proteins fats and carbohydrates   -Phosphorus is a component of nucleic acids (DNA or RNA)","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2002>3>b","subject":"Biology Practical","year":"2002","type":"Practical","sub_label":"b","group":"","topic":"CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS","question":"Make a labelled drawing 8cm to 10cm long of the anterior view of specimen E","images":["data:image/jpeg;base64,"],"marking_scheme":"Anterior view of the femur of a small mammal","marks":"1","difficulty":"2"}];